export enum EncodingType {
  UTF8 = 'UTF-8',
  CP949 = 'CP949',
  EUCKR = 'EUC-KR',
  UTF16LE = 'UTF-16LE',
  UTF16BE = 'UTF-16BE',
}

export interface DecodedResult {
  encoding: EncodingType;
  text: string;
  isError: boolean;
  errorMessage?: string;
  hasReplacementChars: boolean; // For warning state ()
}

export interface HexValidationResult {
  isValid: boolean;
  normalizedHex: string;
  error?: string;
  bytes?: Uint8Array;
}

import { HexValidationResult } from '../types';

export const normalizeHex = (input: string): string => {
  // Remove whitespace, newlines, and '0x' prefix
  return input.replace(/[\s\n\r]/g, '').replace(/^0x/i, '');
};

export const validateAndParseHex = (input: string): HexValidationResult => {
  const normalized = normalizeHex(input);

  if (!normalized) {
    return { isValid: true, normalizedHex: '', bytes: new Uint8Array(0) };
  }

  // Check for non-hex characters
  if (!/^[0-9a-fA-F]*$/.test(normalized)) {
    return {
      isValid: false,
      normalizedHex: normalized,
      error: 'Contains invalid hexadecimal characters (0-9, A-F only).',
    };
  }

  // Check for even length
  if (normalized.length % 2 !== 0) {
    return {
      isValid: false,
      normalizedHex: normalized,
      error: 'Hex string length is odd. Each byte requires 2 characters.',
    };
  }

  try {
    const bytes = new Uint8Array(normalized.length / 2);
    for (let i = 0; i < normalized.length; i += 2) {
      bytes[i / 2] = parseInt(normalized.substring(i, i + 2), 16);
    }
    return { isValid: true, normalizedHex: normalized, bytes };
  } catch (e) {
    return {
      isValid: false,
      normalizedHex: normalized,
      error: 'Failed to parse byte array.',
    };
  }
};

export const formatBytePreview = (bytes: Uint8Array, limit = 16): string => {
  if (bytes.length === 0) return '';
  const subset = Array.from(bytes.slice(0, limit));
  const hexStr = subset.map(b => b.toString(16).padStart(2, '0').toUpperCase()).join(' ');
  return bytes.length > limit ? `${hexStr} ...` : hexStr;
};

import { DecodedResult, EncodingType } from '../types';

const getBrowserLabel = (encoding: EncodingType): string => {
  switch (encoding) {
    case EncodingType.UTF8: return 'utf-8';
    case EncodingType.UTF16LE: return 'utf-16le';
    case EncodingType.UTF16BE: return 'utf-16be';
    // Most browsers map 'euc-kr' to the Encoding Standard's 'euc-kr' which includes CP949 extensions.
    case EncodingType.CP949: return 'euc-kr'; 
    case EncodingType.EUCKR: return 'euc-kr';
    default: return 'utf-8';
  }
};

export const decodeBytes = (bytes: Uint8Array, encoding: EncodingType): DecodedResult => {
  try {
    const label = getBrowserLabel(encoding);
    const decoder = new TextDecoder(label, { fatal: false });
    const text = decoder.decode(bytes);

    // Check for replacement character U+FFFD which indicates decoding issues
    const hasReplacementChars = text.includes('\uFFFD');

    return {
      encoding,
      text,
      isError: false,
      hasReplacementChars,
    };
  } catch (error) {
    let errorMessage = "Unknown decoding error";
    if (error instanceof RangeError) {
      errorMessage = `The encoding '${encoding}' is not supported by this browser.`;
    } else if (error instanceof Error) {
      errorMessage = error.message;
    }

    return {
      encoding,
      text: '',
      isError: true,
      errorMessage,
      hasReplacementChars: false,
    };
  }
};

