import React, { useState, useEffect, useCallback, useRef } from 'react';
import { validateAndParseHex, formatBytePreview } from './utils/hex';
import { decodeBytes } from './services/decoder';
import { EncodingType, DecodedResult, HexValidationResult } from './types';
import { Card } from './components/ui/Card';
import { Button } from './components/ui/Button';
import { ResultCard } from './components/ResultCard';
import { Zap, Trash2, RefreshCw, AlertOctagon, Terminal } from 'lucide-react';

const SUPPORTED_ENCODINGS = [
  EncodingType.UTF8,
  EncodingType.CP949,
  EncodingType.EUCKR,
  EncodingType.UTF16LE,
  EncodingType.UTF16BE,
];

export default function App() {
  const [inputHex, setInputHex] = useState('');
  const [isInstant, setIsInstant] = useState(false);
  const [validation, setValidation] = useState<HexValidationResult | null>(null);
  const [results, setResults] = useState<DecodedResult[]>([]);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Debounce logic for Instant Mode
  const [debouncedHex, setDebouncedHex] = useState('');
  useEffect(() => {
    if (!isInstant) return;
    const timer = setTimeout(() => {
      setDebouncedHex(inputHex);
    }, 300);
    return () => clearTimeout(timer);
  }, [inputHex, isInstant]);

  const performConversion = useCallback((hexInput: string) => {
    const valResult = validateAndParseHex(hexInput);
    setValidation(valResult);

    if (valResult.isValid && valResult.bytes && valResult.bytes.length > 0) {
      const newResults = SUPPORTED_ENCODINGS.map(enc => 
        decodeBytes(valResult.bytes!, enc)
      );
      setResults(newResults);
    } else {
      setResults([]);
    }
  }, []);

  // Effect to trigger conversion on debounce
  useEffect(() => {
    if (isInstant) {
      performConversion(debouncedHex);
    }
  }, [debouncedHex, isInstant, performConversion]);

  const handleManualConvert = () => {
    performConversion(inputHex);
  };

  const handleReset = () => {
    setInputHex('');
    setResults([]);
    setValidation(null);
    if (textareaRef.current) textareaRef.current.focus();
  };

  return (
    <div className="min-h-screen bg-slate-50 py-8 px-4 sm:px-6 lg:px-8 font-sans">
      <div className="max-w-7xl mx-auto space-y-8">

        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold tracking-tight text-slate-900 flex items-center gap-3">
              <span className="p-2 bg-indigo-600 rounded-lg text-white">
                <Terminal className="h-6 w-6" />
              </span>
              HexDecoder Pro
            </h1>
            <p className="mt-2 text-slate-500">
              글자 깨짐(Mojibake) 및 인코딩 문제를 진단하기 위해 HEX 값을 다양한 텍스트 형식으로 즉시 변환하세요.
            </p>
          </div>
          <div className="flex items-center gap-3">
            <button
              onClick={() => setIsInstant(!isInstant)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium transition-colors ${
                isInstant 
                  ? 'bg-amber-100 text-amber-800 ring-1 ring-amber-200' 
                  : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
              }`}
            >
              <Zap className={`h-4 w-4 ${isInstant ? 'fill-current' : ''}`} />
              즉시 변환 모드: {isInstant ? '켜짐' : '꺼짐'}
            </button>
          </div>
        </div>

        {/* Input Section */}
        <Card className="p-1 shadow-md border-indigo-100 ring-1 ring-black/5 bg-white">
          <div className="p-4 md:p-6 space-y-4">
            <div className="flex justify-between items-center mb-1">
              <label htmlFor="hex-input" className="block text-sm font-medium text-slate-700">
                HEX 입력
              </label>
              <span className="text-xs text-slate-400">
                '0x' 접두사, 공백, 줄바꿈 허용
              </span>
            </div>

            <textarea
              id="hex-input"
              ref={textareaRef}
              value={inputHex}
              onChange={(e) => setInputHex(e.target.value)}
              placeholder="예: 48 65 6c 6c 6f 20 57 6f 72 6c 64"
              className="block w-full rounded-lg border-slate-300 bg-slate-50 p-4 text-slate-900 font-mono text-sm shadow-inner focus:border-indigo-500 focus:ring-indigo-500 min-h-[140px] resize-y"
              spellCheck={false}
            />

            {/* Validation & Byte Preview */}
            <div className="min-h-[24px]">
               {validation && !validation.isValid && (
                 <div className="flex items-center gap-2 text-red-600 text-sm animate-in fade-in slide-in-from-top-1 duration-200">
                   <AlertOctagon className="h-4 w-4" />
                   {validation.error}
                 </div>
               )}
               {validation && validation.isValid && validation.bytes && validation.bytes.length > 0 && (
                 <div className="flex flex-wrap items-center gap-x-4 gap-y-2 text-xs text-slate-500 font-mono">
                   <span className="bg-slate-100 px-2 py-0.5 rounded text-slate-600 font-bold">
                     길이: {validation.bytes.length} 바이트
                   </span>
                   <span className="truncate max-w-full">
                     미리보기: {formatBytePreview(validation.bytes, 24)}
                   </span>
                 </div>
               )}
            </div>

            {/* Actions */}
            <div className="flex flex-col sm:flex-row gap-3 pt-2">
              <Button 
                onClick={handleManualConvert} 
                disabled={!inputHex || (isInstant && !!validation?.isValid)}
                className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white shadow-md shadow-indigo-200"
                size="lg"
              >
                <RefreshCw className={`mr-2 h-4 w-4 ${isInstant ? 'hidden' : ''}`} />
                {isInstant ? '변환 중...' : '변환하기'}
              </Button>
              <Button 
                variant="outline" 
                onClick={handleReset}
                className="sm:w-32 border-slate-200 hover:bg-slate-50 hover:text-slate-900"
                size="lg"
              >
                <Trash2 className="mr-2 h-4 w-4 text-slate-500" />
                초기화
              </Button>
            </div>
          </div>
        </Card>

        {/* Results Grid */}
        {results.length > 0 && (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-lg font-semibold text-slate-800">디코딩 결과</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-3 gap-6">
              {results.map((result) => (
                <ResultCard key={result.encoding} result={result} />
              ))}
            </div>
          </div>
        )}

        {/* Empty State / Hint */}
        {results.length === 0 && !validation?.error && (
          <div className="text-center py-12 border-2 border-dashed border-slate-200 rounded-xl">
            <p className="text-slate-400 text-sm">
              위 입력창에 유효한 HEX 코드를 입력하면 여러 인코딩 결과를 동시에 확인할 수 있습니다.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { DecodedResult } from '../types';
import { Card, CardHeader, CardTitle, CardContent, CardFooter } from './ui/Card';
import { Badge } from './ui/Badge';
import { Button } from './ui/Button';
import { Copy, Check, AlertCircle, AlertTriangle } from 'lucide-react';

interface ResultCardProps {
  result: DecodedResult;
}

export const ResultCard: React.FC<ResultCardProps> = ({ result }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(result.text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Determine Badge Status
  let statusBadge;
  if (result.isError) {
    statusBadge = <Badge variant="destructive">오류</Badge>;
  } else if (result.hasReplacementChars) {
    statusBadge = <Badge variant="warning">부분 손실</Badge>;
  } else {
    statusBadge = <Badge variant="success">성공</Badge>;
  }

  return (
    <Card className="flex flex-col h-full hover:border-primary/50 transition-colors duration-200">
      <CardHeader className="pb-3 flex flex-row items-center justify-between space-y-0">
        <CardTitle className="text-base font-medium">
          {result.encoding}
        </CardTitle>
        {statusBadge}
      </CardHeader>

      <CardContent className="flex-1 min-h-[120px]">
        {result.isError ? (
          <div className="h-full flex flex-col items-center justify-center text-center p-4 bg-destructive/10 rounded-md border border-destructive/20">
             <AlertCircle className="h-6 w-6 text-destructive mb-2" />
             <p className="text-sm text-destructive font-medium">{result.errorMessage}</p>
          </div>
        ) : (
          <div className="relative h-full group">
            {result.text.length === 0 ? (
               <div className="h-full flex items-center justify-center text-muted-foreground text-sm italic">
                 (결과 없음)
               </div>
            ) : (
              <div className="h-full max-h-[200px] overflow-y-auto whitespace-pre-wrap break-all rounded-md bg-muted/50 p-3 text-sm font-mono text-foreground border border-border">
                {result.text}
              </div>
            )}

            {result.hasReplacementChars && (
              <div className="mt-2 flex items-center gap-2 text-xs text-amber-600 dark:text-amber-500">
                <AlertTriangle className="h-3 w-3" />
                <span>대체 문자(\uFFFD) 포함됨 (깨짐 발생)</span>
              </div>
            )}
          </div>
        )}
      </CardContent>

      <CardFooter className="pt-0 justify-end">
        <Button 
          variant="outline" 
          size="sm" 
          onClick={handleCopy} 
          disabled={result.isError || !result.text}
          className="gap-2"
        >
          {copied ? <Check className="h-4 w-4 text-emerald-500" /> : <Copy className="h-4 w-4" />}
          {copied ? '복사됨' : '복사'}
        </Button>
      </CardFooter>
    </Card>
  );
};

